package workshop_03;

public class Work01 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		for(int i =2 ; i<= 20;i +=2 ) {
			System.out.println(i);
		}

		for(int i =3 ; i<= 20;i +=3 ) {
			System.out.println(i);
		}
		int sum = 0;
		for(int i =1 ; i<= 20;i ++ ) {
			sum += i;
			
		}
		System.out.println(sum);

		sum = 0;
		for(int i =2 ; i<= 20;i +=2 ) {
			sum += i;
			
		}
		System.out.println(sum);

	}

}
